module pipelined_adder (
    input wire clk,
    input wire [4:0] A,
    input wire [4:0] B,
    output reg [5:0] SUM
);
    reg [5:0] obf_stage1_sum;

    // Stage 1: Calculate sum
    always @(posedge clk) begin
        obf_stage1_sum <= A + B;
    end

    // Stage 2: Output the result
    always @(posedge clk) begin
        SUM <= obf_stage1_sum;
    end
endmodule
